proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_not_eventually_implies_always_not(ex: Execution<int>, p: TempPred<int>)
    requires
        not(eventually(p)).satisfied_by(ex),
    ensures
        always(not(p)).satisfied_by(ex),
{
    not_eventually_unfold::<int>(ex, p);
}

proof fn phi_3_always_p_or_eventually_q_rec_no_bound(ex: Execution<int>, next: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        forall |idx| p.satisfied_by(ex.suffix(idx)) && next.satisfied_by(ex.suffix(idx)) ==> p.satisfied_by(ex.suffix(idx + 1)) || q.satisfied_by(ex.suffix(idx + 1)),
        forall |idx| next.satisfied_by(#[trigger] ex.suffix(idx)),
        forall |idx| !q.satisfied_by(#[trigger] ex.suffix(idx)),
        p.satisfied_by(ex),
    ensures
        forall |i: nat| p.satisfied_by(#[trigger] ex.suffix(i)),
{
    assert forall |i: nat| p.satisfied_by(#[trigger] ex.suffix(i)) by {
        always_p_or_eventually_q_rec::<int>(ex, next, p, q, i);
    };
}

proof fn phi_4_suffix_composition_via_execution_equality(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality::<int>(ex.suffix(i).suffix(j), ex.suffix(i + j));
}

proof fn phi_5_always_propagate_then_unfold_double_suffix(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i).suffix(j)),
{
    always_propagate_forwards::<int>(ex, p, i);
    always_unfold::<int>(ex.suffix(i), p);
}
